sys_script_include.script:
var VendorRenewalAjax = Class.create();
VendorRenewalAjax.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    getVendorDetails: function() {
        var vendorSysId = this.getParameter('sysparm_vendor_sys_id');

        if (!vendorSysId) {
            return global.JSON.stringify({ error: 'No ID provided' });
        }

        var gr = new GlideRecord('x_1956461_vendor_0_vendor_table');

        if (gr.get(vendorSysId)) {
            var results = {
                // Matches "Vendor Code" column label -> maps to "number" database column
                vendor_code: gr.getValue('number') || '',

                // Matches "Vendor Name" column label -> maps to "vendor_name" database column
                vendor_name: gr.getValue('vendor_name') || '',

                // Pure string field -> safe to pull directly via getValue()
                vendor_contact: gr.getValue('vendor_contact') || '',

                // For choice fields, grab the internal database value (e.g. 'draft')
                state: gr.getValue('state') || '',

                // REFERENCE FIELD HANDLING: Extract both the raw Sys ID and Display Name
                vendor_manager_id: gr.getValue('vendor_manager') || '',
                vendor_manager_dv: gr.vendor_manager ? gr.vendor_manager.getDisplayValue() : ''
            };

            return global.JSON.stringify(results);
        }

        return global.JSON.stringify({ error: 'Vendor record not found' });
    },

    type: 'VendorRenewalAjax'
});
